class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        def manacher(seq):
            T = '#'.join('^{}$'.format(seq))
            n = len(T)
            P = [0] * n
            C = R = 0
            for i in range(1, n - 1):
                mir = 2 * C - i
                if i < R:
                    P[i] = min(R - i, P[mir])
                while T[i + 1 + P[i]] == T[i - 1 - P[i]]:
                    P[i] += 1
                if i + P[i] > R:
                    C, R = i, i + P[i]
            return P

        def longest_pal_substr(seq):
            P = manacher(seq)
            max_len = 0
            for i, l in enumerate(P):
                if l > max_len:
                    max_len = l
            return max_len

        max_single = max(longest_pal_substr(s), longest_pal_substr(t))

        combined = s + '#' + t
        max_combined = longest_pal_substr(combined)

        max_len = max(max_single, max_combined)

        n, m = len(s), len(t)
        dp = [[0] * (m + 1) for _ in range(n + 1)]
        max_concat = 0

        for i in range(1, n + 1):
            for j in range(1, m + 1):
                if s[i - 1] == t[m - j]:
                    dp[i][j] = dp[i - 1][j - 1] + 1
                    max_concat = max(max_concat, dp[i][j])
                else:
                    dp[i][j] = 0

        return max(max_len, max_concat * 2)
